package com.google.protobuf

// Compile-time stub for the @Generated annotation emitted by protoc in proto/kotlin/.
// The real class lives in protobuf-java (non-lite), which we don't ship on Android.
// SOURCE retention means this annotation is erased from .class files — zero runtime impact.
// FILE covers Kotlin `@file:Generated`; CLASS covers Java `@Generated` on class declarations.
@Target(AnnotationTarget.FILE, AnnotationTarget.CLASS)
@Retention(AnnotationRetention.SOURCE)
annotation class Generated
